36: /**
37:  * A custom classloader dedicated to loading Connect plugin classes in classloading isolation.
38:  *
39:  * <p>
40:  * Under the current scheme for classloading isolation in Connect, the delegating classloader loads
41:  * plugin classes that it finds in its child plugin classloaders. For classes that are not plugins,
42:  * this delegating classloader delegates its loading to its parent. This makes this classloader a
43:  * child-first classloader.
44:  * <p>
45:  * This class is thread-safe and parallel capable.
46:  */
47: public class DelegatingClassLoader extends URLClassLoader {
48:     private static final Logger log = LoggerFactory.getLogger(DelegatingClassLoader.class);
49: 
50:     private final ConcurrentMap<String, SortedMap<PluginDesc<?>, ClassLoader>> pluginLoaders;
51:     private final ConcurrentMap<String, String> aliases;
52: 
53:     // Although this classloader does not load classes directly but rather delegates loading to a
54:     // PluginClassLoader or its parent through its base class, because of the use of inheritance
55:     // in the latter case, this classloader needs to also be declared as parallel capable to use
56:     // fine-grain locking when loading classes.
57:     static {
58:         ClassLoader.registerAsParallelCapable();
59:     }
60: 
61:     public DelegatingClassLoader(ClassLoader parent) {
62:         super(new URL[0], parent);
63:         this.pluginLoaders = new ConcurrentHashMap<>();
64:         this.aliases = new ConcurrentHashMap<>();
65:     }
66: 
67:     public DelegatingClassLoader() {
68:         // Use as parent the classloader that loaded this class. In most cases this will be the
69:         // System classloader. But this choice here provides additional flexibility in managed
70:         // environments that control classloading differently (OSGi, Spring and others) and don't
71:         // depend on the System classloader to load Connect's classes.
72:         this(DelegatingClassLoader.class.getClassLoader());
73:     }
74: 
